const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

export interface ChatMessage { role: "user" | "assistant"; content: string; }
export interface ActivitySuggestion { title: string; description: string; duration: string; category: string; emoji: string; }
export interface MusicTrack { title: string; artist: string; spotify_url: string; youtube_url: string; reason: string; }
export interface ChatResponse {
  response: string; detected_emotion: string; mood_level: string;
  response_mode: string; activities: ActivitySuggestion[];
  celebration_message: string | null; special_action: string | null;
  special_content: string | null; music_tracks: MusicTrack[] | null;
  joke: string | null; proverb: string | null; proverb_author: string | null;
  session_id: string; wellness_tip: string | null; llm_provider: string | null;
}
export interface VoiceAnalysisResponse {
  transcribed_text: string; detected_emotion: string; mood_level: string;
  confidence: number; chat_response: ChatResponse;
}

/**
 * Get or create a persistent anonymous user ID stored in localStorage.
 * This ensures every conversation is saved to Supabase even without auth.
 * When your auth teammate integrates, replace this with the real user ID.
 */
export function getOrCreateUserId(): string {
  if (typeof window === "undefined") return "anonymous";
  const key = "neuronest_user_id";
  let userId = localStorage.getItem(key);
  if (!userId) {
    userId = `user-${crypto.randomUUID()}`;
    localStorage.setItem(key, userId);
  }
  return userId;
}

export async function sendChatMessage(
  message: string,
  history: ChatMessage[],
  sessionId?: string,
  userId?: string,
): Promise<ChatResponse> {
  const effectiveUserId = userId || getOrCreateUserId();
  const res = await fetch(`${API_BASE}/api/chat/`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      message,
      conversation_history: history,
      session_id: sessionId,
      user_id: effectiveUserId,   // always send user_id so data saves to Supabase
    }),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Failed");
  }
  return res.json();
}

export async function analyzeVoice(audioBlob: Blob, sessionId?: string): Promise<VoiceAnalysisResponse> {
  const formData = new FormData();
  formData.append("audio", audioBlob, "recording.webm");
  if (sessionId) formData.append("session_id", sessionId);
  const userId = getOrCreateUserId();
  formData.append("user_id", userId);
  const res = await fetch(`${API_BASE}/api/voice/analyze`, { method: "POST", body: formData });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.detail || "Voice failed");
  }
  return res.json();
}
