import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) { return twMerge(clsx(inputs)); }

export const MOOD_EMOJI: Record<string, string> = { very_bad: "😔", bad: "😕", neutral: "😐", good: "🙂", very_good: "😄" };
export const MOOD_COLOR: Record<string, string> = { very_bad: "text-red-400", bad: "text-orange-400", neutral: "text-yellow-400", good: "text-green-400", very_good: "text-emerald-400" };
export const EMOTION_EMOJI: Record<string, string> = { stressed: "😤", anxious: "😰", sad: "😢", angry: "😠", happy: "😊", calm: "😌", overwhelmed: "🤯", lonely: "🥺", excited: "🤩", neutral: "😐" };
export const CATEGORY_COLOR: Record<string, string> = { breathing: "bg-blue-500/20 text-blue-300", mindfulness: "bg-purple-500/20 text-purple-300", movement: "bg-green-500/20 text-green-300", social: "bg-pink-500/20 text-pink-300", creative: "bg-amber-500/20 text-amber-300" };
export function formatMoodLabel(mood: string): string { return mood.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()); }
